from flask import Flask, session, request
import redis

app = Flask(__name__)

# Connect to Redis server at localhost:6379 using redis-py library
redis_client = redis.Redis(host='localhost', port=6379, db=0)

# Define a caching decorator for expensive database queries
def cache(func):
    def wrapper(*args, **kwargs):
        key = f'{func.__name__}-{args[0]}'
        value = redis_client.get(key)
        if value is not None:
            return value
        else:
            result = func(*args, **kwargs)
            redis_client.set(key, result)
            return result
    return wrapper

# Define a session storage decorator using Redis
def session_storage(func):
    def wrapper(*args, **kwargs):
        key = f'{func.__name__}-{args[0]}'
        value = redis_client.get(key)
        if value is not None:
            return value
        else:
            result = func(*args, **kwargs)
            redis_client.set(key, result)
            return result
    return wrapper

# Define a route for the home page
@app.route('/')
def index():
    # Use the session storage decorator to store and retrieve user sessions
    @session_storage
    def get_user_sessions():
        return redis_client.smembers('user_sessions')
    
    # Use the caching decorator for expensive database queries
    @cache
    def get_user_data(user_id):
        return {'name': f'User {user_id}', 'email': f'user{user_id}@example.com'}
    
    user_sessions = get_user_sessions()
    user_data = {}
    for session in user_sessions:
        user_id = int(session.split('-')[1])
        user_data[user_id] = get_user_data(user_id)
    
    return render_template('index.html', user_data=user_data)

if __name__ == '__main__':
    app.run(debug=True)